using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    // ── ChargeAsync ─────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid_visa", -10m));
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.ChargeAsync(null!, 25m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("", 25m));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 100m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    // ── RefundAsync ─────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(""));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(result.Success);
    }

    // ── Integration-style scenarios ─────────────────────────────

    [TestMethod]
    public async Task ChargeAndRefund_FullLifecycle_BothSucceed()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 75m);
        Assert.IsTrue(charge.Success);

        var refund = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsTrue(refund.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_MultipleCharges_ReturnUniqueIds()
    {
        var first  = await _gateway.ChargeAsync("tok_valid_visa", 10m);
        var second = await _gateway.ChargeAsync("tok_valid_visa", 20m);

        Assert.AreNotEqual(first.ChargeId, second.ChargeId);
    }
}

